import React, { useState } from 'react';
import './WordCloud.css';

const questions = [
  { text: 'Tell me about this data', size: 'xl' },
  { text: 'What are the top trends?', size: 'lg' },
  { text: 'Summarise the key insights', size: 'xl' },
  { text: 'Who are the top performers?', size: 'md' },
  { text: 'Show me year-over-year growth', size: 'lg' },
  { text: "What's driving performance?", size: 'md' },
  { text: 'Where are the biggest opportunities?', size: 'sm' },
];

export default function WordCloud({ onSelect }) {
  const [active, setActive] = useState(null);

  const handleClick = (q) => {
    setActive(q.text);
    onSelect(q.text);
    setTimeout(() => setActive(null), 1500);
  };

  return (
    <div className="word-cloud-section">
      <p className="word-cloud-label">Try asking Spotter…</p>
      <div className="word-cloud">
        {questions.map((q) => (
          <button
            key={q.text}
            className={`wc-chip wc-${q.size} ${active === q.text ? 'wc-active' : ''}`}
            onClick={() => handleClick(q)}
          >
            {q.text}
          </button>
        ))}
      </div>
    </div>
  );
}
